import { useNavigate } from "react-router-dom"
export type Botao={
    nome:string;
    action:()=>void;  
}
export const PageHomeUsuario = () => {
    const navigation=useNavigate()
const botoes:Botao[]=[
    {nome:"Agendar", action:()=>{navigation("/novoAgendamento")}},
    {nome:"Meus Agendamentos", action:()=>{navigation("/agendas")}}                
]
    return(
        <div>
            <h1>Home Usuário</h1>
            {botoes.map((botao)=>
            <button onClick={botao.action}>{botao.nome}</button>)}
        </div>
    )
}
